 void wallet(boolean recovery){try{JSONObject q=new JSONObject();DateTimeFormatter fmt=DateTimeFormatter.ofPattern("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'").withZone(ZoneOffset.UTC);q.put("version","1");q.put("nonce",nonce());q.put("chainId","ynx_6423-1");q.put("requestingProduct","calendar");q.put("productClientId",CLIENT);q.put("bundleId",BUNDLE);q.put("productDeviceAlgorithm","p256-sha256");q.put("productDeviceKey",key());q.put("callback",CALLBACK);q.put("scopes",new JSONArray().put(recovery?"calendar:recover":"calendar:account"));q.put("purpose",recovery?"Recover YNX Calendar on this device":"Sign in to YNX Calendar on this device");q.put("issuedAt",fmt.format(Instant.now()));q.put("expiresAt",fmt.format(Instant.now().plusSeconds(300)));getSharedPreferences("ynx_calendar",MODE_PRIVATE).edit().putString("pending_request",canonical(q)).apply();String e=Base64.getUrlEncoder().withoutPadding().encodeToString(canonical(q).getBytes(StandardCharsets.UTF_8));startActivity(new Intent(Intent.ACTION_VIEW,Uri.parse("ynxwallet://authorize?request="+e)));}catch(Exception e){status.setText(getString(R.string.unavailable)+": "+e.getClass().getSimpleName());}}
 void callback(Intent i){if(i==null||i.getData()==null)return;try{Uri u=i.getData();if(!"ynxcalendar".equals(u.getScheme())||!"wallet-auth".equals(u.getHost())||!"/callback".equals(u.getPath())||u.getFragment()!=null||!u.getQueryParameterNames().equals(Collections.singleton("response")))throw new SecurityException();String encoded=u.getQueryParameter("response"),pending=p.getString("pending_request",null);if(encoded==null||pending==null)throw new SecurityException();JSONObject response=new JSONObject(new String(Base64.getUrlDecoder().decode(encoded),StandardCharsets.UTF_8)),request=new JSONObject(pending);for(String k:Arrays.asList("version","nonce","chainId","requestingProduct","productClientId","bundleId","productDeviceAlgorithm","productDeviceKey","callback","purpose"))if(!request.getString(k).equals(response.getString(k)))throw new SecurityException();if(!request.getJSONArray("scopes").toString().equals(response.getJSONArray("scopes").toString()))throw new SecurityException();String nonce=response.getString("nonce");if(p.getBoolean("consumed."+nonce,false))throw new SecurityException();String expected=hex(MessageDigest.getInstance("SHA-256").digest(("YNX_WALLET_AUTH_REQUEST_V1\n"+canonical(request)).getBytes(StandardCharsets.UTF_8)));if(!expected.equals(response.getString("requestDigest")))throw new SecurityException();p.edit().putBoolean("consumed."+nonce,true).putString("wallet_response",canonical(response)).apply();status.setText(getString(R.string.unavailable));}catch(Exception e){status.setText(getString(R.string.security));}}
 String hex(byte[]v){StringBuilder b=new StringBuilder();for(byte x:v)b.append(String.format("%02x",x));return b.toString();}
 String canonical(Object v)throws JSONException{if(v==JSONObject.NULL)return "null";if(v instanceof String)return JSONObject.quote((String)v);if(v instanceof JSONArray){JSONArray a=(JSONArray)v;StringBuilder b=new StringBuilder("[");for(int i=0;i<a.length();i++){if(i>0)b.append(",");b.append(canonical(a.get(i)));}return b.append("]").toString();}if(v instanceof JSONObject){JSONObject o=(JSONObject)v;ArrayList<String>k=new ArrayList<>();o.keys().forEachRemaining(k::add);Collections.sort(k);StringBuilder b=new StringBuilder("{");for(int i=0;i<k.size();i++){if(i>0)b.append(",");b.append(JSONObject.quote(k.get(i))).append(":").append(canonical(o.get(k.get(i))));}return b.append("}").toString();}return String.valueOf(v);}
 String key()throws Exception{KeyStore ks=KeyStore.getInstance("AndroidKeyStore");ks.load(null);String a="ynx_calendar_product_device";if(!ks.containsAlias(a)){KeyPairGenerator g=KeyPairGenerator.getInstance(KeyProperties.KEY_ALGORITHM_EC,"AndroidKeyStore");g.initialize(new KeyGenParameterSpec.Builder(a,KeyProperties.PURPOSE_SIGN|KeyProperties.PURPOSE_VERIFY).setDigests(KeyProperties.DIGEST_SHA256).setAlgorithmParameterSpec(new java.security.spec.ECGenParameterSpec("secp256r1")).build());g.generateKeyPair();}ECPublicKey k=(ECPublicKey)ks.getCertificate(a).getPublicKey();byte[]o=new byte[33],x=fixed(k.getW().getAffineX());o[0]=(byte)(k.getW().getAffineY().testBit(0)?3:2);System.arraycopy(x,0,o,1,32);return Base64.getUrlEncoder().withoutPadding().encodeToString(o);}byte[]fixed(BigInteger n){byte[]b=n.toByteArray(),o=new byte[32];System.arraycopy(b,Math.max(0,b.length-32),o,Math.max(0,32-b.length),Math.min(32,b.length));return o;}String nonce(){byte[]b=new byte[32];new SecureRandom().nextBytes(b);return Base64.getUrlEncoder().withoutPadding().encodeToString(b);}
 void applyLocale(){String l=p==null?"system":p.getString("locale","system");AppCompatDelegate.setApplicationLocales("system".equals(l)?LocaleListCompat.getEmptyLocaleList():LocaleListCompat.forLanguageTags(l));}boolean online(){ConnectivityManager c=(ConnectivityManager)getSystemService(CONNECTIVITY_SERVICE);Network n=c.getActiveNetwork();NetworkCapabilities x=n==null?null:c.getNetworkCapabilities(n);return x!=null&&x.hasCapability(NetworkCapabilities.NET_CAPABILITY_INTERNET);}TextView t(String s,int z,boolean b){TextView v=new TextView(this);v.setText(s);v.setTextSize(z);v.setTextColor(Color.parseColor("#101828"));v.setTypeface(null,b?1:0);v.setPadding(0,dp(6),0,dp(6));return v;}TextView sec(String s){TextView v=t(s,20,true);v.setPadding(0,dp(22),0,dp(8));return v;}EditText in(String h){EditText e=new EditText(this);e.setHint(h);return e;}Button btn(String s,View.OnClickListener l){Button b=new Button(this);b.setText(s);b.setAllCaps(false);b.setOnClickListener(l);return b;}int dp(int n){return(int)(n*getResources().getDisplayMetrics().density);}
